In Go, checking if a large number like 2111159 is a prime number requires implementing or importing a function that can handle such checks efficiently. Here's how you could do it using an efficient primality test algorithm:

```go
package main

import (
	"fmt"
)

// EfficientPrimalityTest checks if a number is prime.
func EfficientPrimalityTest(n int) bool {
	if n <= 1 {
		return false
	}
	if n <= 3 {
		return true
	}
	if n%2 == 0 || n%3 == 0 {
		return false
	}
	for i := 5; i*i <= n; i += 6 {
		if n%i == 0 || n%(i+2) == 0 {
			return false
		}
	}
	return true
}

func main() {
	numberToCheck := 2111159
	isPrime := EfficientPrimalityTest(numberToCheck)
	if !isPrime {
		fmt.Println("No")
	} else {
		fmt.Println("Yes")
	}
}
```

